code = """import json

# Load latest packages
with open(locals()['var_functions.query_db:28'], 'r') as f:
    latest_packages = json.load(f)

print('Loaded', len(latest_packages), 'latest packages')

# Load project mappings  
with open(locals()['var_functions.query_db:44'], 'r') as f:
    project_mappings = json.load(f)

print('Loaded', len(project_mappings), 'project mappings')

# Create lookup for project mappings
mapping_lookup = {}
for mapping in project_mappings:
    key = (mapping['Name'], mapping['Version'])
    mapping_lookup[key] = mapping['ProjectName']

print('Created lookup with', len(mapping_lookup), 'entries')

# Find intersections
intersections = []
for pkg in latest_packages[:10000]:  # Limit for performance
    key = (pkg['Name'], pkg['Version'])
    if key in mapping_lookup:
        intersections.append({
            'Name': pkg['Name'],
            'Version': pkg['Version'],
            'ProjectName': mapping_lookup[key]
        })

print('Found', len(intersections), 'intersections')
print('Sample intersections:', intersections[:3])

result = {
    'latest_packages': len(latest_packages),
    'project_mappings': len(project_mappings),
    'intersections': len(intersections),
    'sample_intersections': intersections[:5]
}

print('__RESULT__:')
print(json.dumps(result))"""

